from flask import Flask, jsonify

app = Flask(__name__)

@app.route('/')
def index():
    return 'Hello OPC'

@app.route('/health')
def health():
    return jsonify({'status': 'ok', 'message': 'server is running'}), 200

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)
